10" stroke="#8899bb" stroke-width="1.4"/><line x1="432" y1="170" x2="432" y2="214" stroke="#8899bb" stroke-width="1.4"/><line x1="330" y1="220" x2="418" y2="220" stroke="#8899bb" stroke-width="1.4"/><line x1="418" y1="213" x2="418" y2="231" stroke="#8899bb" stroke-width="1.4"/><line x1="424" y1="208" x2="424" y2="236" stroke="#8899bb" stroke-width="1.4"/><line x1="424" y1="214" x2="432" y2="214" stroke="#8899bb" stroke-width="1.4"/><line x1="424" y1="236" x2="432" y2="236" stroke="#8899bb" stroke-width="1.4"/><line x1="432" y1="236" x2="432" y2="258" stroke="#8899bb" stroke-width="1.4"/><text x="447" y="226" fill="#00d4ff" font-size="11" text-anchor="middle" font-family="monospace">Q1</text><circle cx="432" cy="246" r="2.6" fill="#8899bb"/><line x1="432" y1="246" x2="350" y2="246" stroke="#8899bb" stroke-width="1.4"/><line x1="350" y1="246" x2="350" y2="258" stroke="#8899bb" stroke-width="1.4"/><line x1="350" y1="258" x2="330" y2="258" stroke="#8899bb" stroke-width="1.4"/><rect x="425" y="258" width="14" height="34" fill="none" stroke="#8899bb" stroke-width="1.4"/><text x="447" y="278" fill="#c8d4ee" font-size="9" text-anchor="start" font-family="monospace">Rs</text><line x1="432" y1="292" x2="432" y2="310" stroke="#8899bb" stroke-width="1.4"/><line x1="477" y1="90" x2="477" y2="70" stroke="#8899bb" stroke-width="1.4"/><line x1="477" y1="70" x2="540" y2="70" stroke="#8899bb" stroke-width="1.4"/><polygon points="540,63 540,77 552,70" fill="#8899bb"/><line x1="552" y1="63" x2="552" y2="77" stroke="#8899bb" stroke-width="1.4"/><text x="546" y="59" fill="#c8d4ee" font-size="10" text-anchor="middle" font-family="monospace">D3</text><line x1="552" y1="70" x2="700" y2="70" stroke="#8899bb" stroke-width="1.4"/><circle cx="600" cy="70" r="2.6" fill="#8899bb"/><circle cx="620" cy="70" r="2.6" fill="#8899bb"/><line x1="600" y1="70" x2="600" y2="156" stroke="#8899bb" stroke-width="1.4"/><line x1="600" y1="156" x2="600" y2="172" stroke="#8899bb" stroke-width="1.4"/><line x1="589" y1="172" x2="611" y2="172" stroke="#8899bb" stroke-width="1.4"/><line x1="589" y1="180" x2="611" y2="180" stroke="#8899bb" stroke-width="1.4"/><line x1="600" y1="180" x2="600" y2="196" stroke="#8899bb" stroke-width="1.4"/><text x="616" y="180" fill="#c8d4ee" font-size="10" text-anchor="start" font-family="monospace">Cout</text><line x1="600" y1="196" x2="600" y2="310" stroke="#8899bb" stroke-width="1.4"/><circle cx="600" cy="310" r="2.6" fill="#8899bb"/><text x="688" y="58" fill="#00d4ff" font-size="10" text-anchor="middle" font-family="monospace">VOUT+</text><text x="688" y="296" fill="#00d4ff" font-size="10" text-anchor="middle" font-family="monospace">VOUT-</text><line x1="700" y1="70" x2="700" y2="76" stroke="#8899bb" stroke-width="1.4"/><line x1="700" y1="310" x2="700" y2="304" stroke="#8899bb" stroke-width="1.4"/><line x1="477" y1="170" x2="477" y2="310" stroke="#8899bb" stroke-width="1.4"/><circle cx="477" cy="310" r="2.6" fill="#8899bb"/><line x1="620" y1="70" x2="620" y2="340" stroke="#8899bb" stroke-width="1.4"/><rect x="585" y="340" width="70" height="34" fill="none" stroke="#8899bb" stroke-width="1.4"/><text x="620" y="361" fill="#c8d4ee" font-size="11" text-anchor="middle" font-family="monospace">TL431</text><line x1="585" y1="352" x2="510" y2="352" stroke="#8899bb" stroke-width="1.4"/><rect x="450" y="334" width="60" height="40" fill="none" stroke="#8899bb" stroke-width="1.4"/><text x="480" y="358" fill="#c8d4ee" font-size="11" text-anchor="middle" font-family="monospace">U2</text><text x="480" y="384" fill="#c8d4ee" font-size="8" text-anchor="middle" font-family="monospace">OPTO</text><line x1="450" y1="352" x2="210" y2="352" stroke="#8899bb" stroke-width="1.4"/><line x1="210" y1="352" x2="210" y2="249" stroke="#8899bb" stroke-width="1.4"/><line x1="210" y1="249" x2="240" y2="249" stroke="#8899bb" stroke-width="1.4"/><line x1="430" y1="310" x2="430" y2="352" stroke="#8899bb" stroke-width="1.4"/><line x1="430" y1="352" x2="424" y2="352" stroke="#8899bb" stroke-width="1.4"/><line x1="424" y1="344" x2="424" y2="360" stroke="#8899bb" stroke-width="1.4"/><line x1="416" y1="344" x2="416" y2="360" stroke="#8899bb" stroke-width="1.4"/><line x1="416" y1="352" x2="380" y2="352" stroke="#8899bb" stroke-width="1.4"/><line x1="380" y1="352" x2="380" y2="310" stroke="#8899bb" stroke-width="1.4"/><circle cx="380" cy="310" r="2.6" fill="#8899bb"/><text x="420" y="336" fill="#00d4ff" font-size="9" text-anchor="middle" font-family="monospace">CY</text><line x1="477" y1="20" x2="477" y2="60" stroke="#00d4ff" stroke-width="1" stroke-dasharray="4 3"/><line x1="477" y1="300" x2="477" y2="326" stroke="#00d4ff" stroke-width="1" stroke-dasharray="4 3"/><text x="477" y="14" fill="#00d4ff" font-size="8" text-anchor="middle" font-family="monospace">ISOLATION</text><path d="M432,214 L448,130 L462,130 L477,150 V310 M477,310 H430 V352 H380 V310 M380,310 H432" fill="none" stroke="#22c55e" stroke-width="8" stroke-opacity="0.4" stroke-linecap="round" stroke-linejoin="round"/></svg></div><div style="font-size:12px;margin:4px 0"><span style="display:inline-block;width:10px;height:10px;background:#22c55e;margin:0 4px 0 10px"></span>緑＝信号/ノイズ経路</div><strong>コモンモード経路（緑）：</strong>ノイズ源＝Q1 ドレイン（SW ノード）の高 dv/dt → 巻線間寄生容量 Cps を通って二次側へ → 二次グランドを流れ → <strong>CY を通って一次グランドへ</strong>戻り、ノイズ源へ短絡帰還。<br><strong>CY が無いと：</strong>ノイズ電流は出力ケーブル、人体/大地、LISN を回る大ループでしか戻れず＝伝導コモンモード EMI が即不合格。<br><strong>CY の配置：</strong>一次グランド–二次グランド間（または一次 HV+–二次グランド間）に安全規格 Y1/Y2 コンデンサを跨がせる；容量は漏れ電流で制限（通常 ≤4.7nF、AC アダプタは 1~2.2nF が多い）；トランスに密着させ両端の配線を最短にしてノイズループを最小化。<div class="key-point">コモンモード EMI の考え方は「ノイズに最短の帰り道を与える」——Y コンデンサがその道。</div>$vsq$, $vsq$스위칭 노이즈는 변압기 1·2차 권선 간 기생 커패시턴스를 통해 2차측으로 흘러 공통 모드 EMI가 됩니다. 이 <strong>공통 모드 노이즈 경로</strong>를 표시하고 Y 커패시터(CY)의 역할과 배치 원칙을 설명하세요.$vsq$, $vsq$<div class="exam-diagram-box"><svg viewBox="0 0 720 400" xmlns="http://www.w3.org/2000/svg"><rect width="720" height="400" fill="#0a0a1a"/><text x="16" y="59" fill="#00d4ff" font-size="11" text-anchor="mi